            InputSource inputSource = new InputSource(new StringReader(xmlContent));
            Document document = builder.parse(inputSource);

            XPathFactory xPathFactory = XPathFactory.newInstance();
            XPath xpath = xPathFactory.newXPath();

            String result = (String) xpath.evaluate(xpathExpression, document, XPathConstants.STRING);
            return result == null ? "" : result.trim();
        } catch (ParserConfigurationException | SAXException | IOException | XPathExpressionException e) {
            throw new RuntimeException("Failed to extract metric via XPath: " + e.getMessage(), e);
        }
    }

    /**
     * Creates a securely configured DocumentBuilderFactory to prevent XXE and related attacks.
     */
    private DocumentBuilderFactory createSecureDocumentBuilderFactory() throws ParserConfigurationException {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();

        // Secure processing
        dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

        // Disallow DOCTYPE declaration
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

        // Disable external entities
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

        // Disable DTDs entirely
        dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

        // Additional hardening
        dbf.setXIncludeAware(false);
        dbf.setExpandEntityReferences(false);
        dbf.setNamespaceAware(false);

        return dbf;
        }
}
